from __future__ import annotations

import hashlib
import json
import os
import threading
from dataclasses import dataclass, field
from pathlib import Path
from typing import Any


FORBIDDEN_PROVENANCE = {
    "harvey.criteria",
    "harvey.match_criteria",
    "harvey.scorer_output",
    "harvey.prior_score",
    "harvey.expected_answer",
    "criteria_derived_deliverables",
    "task_id_routing",
}

FORBIDDEN_TEXT_MARKERS = (
    "match_criteria",
    "scorer_output",
    "prior failed criteria",
    "prior passed criteria",
)

_audit_lock = threading.Lock()


@dataclass
class PromptAuditContext:
    stage: str
    output_dir: str = ""
    provenance: list[str] = field(default_factory=list)
    metadata: dict[str, Any] = field(default_factory=dict)


def audit_enabled() -> bool:
    return os.getenv("SWARM_PROMPT_AUDIT", "").strip().lower() in {
        "1", "true", "yes", "on",
    }


def audit_prompt(prompt: str, context: PromptAuditContext | dict | None) -> dict:
    """Record provenance-aware prompt audit metadata.

    This intentionally audits forbidden provenance and a few high-risk literal
    markers. It does not ban clean generated words like "criteria".
    """
    ctx = _normalize_context(context)
    provenance = list(ctx.provenance)
    forbidden_provenance = sorted(set(provenance) & FORBIDDEN_PROVENANCE)
    text_lower = prompt.lower()
    forbidden_text = [
        marker for marker in FORBIDDEN_TEXT_MARKERS
        if marker.lower() in text_lower
    ]
    record = {
        "stage": ctx.stage,
        "prompt_sha256": hashlib.sha256(prompt.encode("utf-8")).hexdigest(),
        "prompt_chars": len(prompt),
        "provenance": provenance,
        "forbidden_provenance_hits": forbidden_provenance,
        "forbidden_text_hits": forbidden_text,
        "metadata": ctx.metadata,
        "redacted_excerpt": prompt[:500],
    }
    if audit_enabled() and ctx.output_dir:
        _append_record(ctx.output_dir, record)
    return record


def _normalize_context(context: PromptAuditContext | dict | None) -> PromptAuditContext:
    if isinstance(context, PromptAuditContext):
        return context
    if isinstance(context, dict):
        provenance = context.get("provenance", [])
        if not isinstance(provenance, list):
            provenance = [str(provenance)]
        metadata = context.get("metadata", {})
        if not isinstance(metadata, dict):
            metadata = {"value": metadata}
        return PromptAuditContext(
            stage=str(context.get("stage", "")),
            output_dir=str(context.get("output_dir", "")),
            provenance=[str(p) for p in provenance],
            metadata=metadata,
        )
    return PromptAuditContext(stage="")


def _append_record(output_dir: str, record: dict) -> None:
    swarm_dir = Path(output_dir) / "swarm"
    swarm_dir.mkdir(parents=True, exist_ok=True)
    path = swarm_dir / "prompt_audit.json"
    with _audit_lock:
        if path.exists():
            try:
                data = json.loads(path.read_text(encoding="utf-8"))
            except json.JSONDecodeError:
                data = {"schema_version": 1, "records": []}
        else:
            data = {"schema_version": 1, "records": []}
        records = data.setdefault("records", [])
        records.append(record)
        data["summary"] = summarize_records(records)
        path.write_text(json.dumps(data, indent=2), encoding="utf-8")


def summarize_records(records: list[dict]) -> dict:
    forbidden_provenance_hits = 0
    forbidden_text_hits = 0
    stages: dict[str, int] = {}
    for record in records:
        forbidden_provenance_hits += len(record.get("forbidden_provenance_hits") or [])
        forbidden_text_hits += len(record.get("forbidden_text_hits") or [])
        stage = str(record.get("stage") or "unknown")
        stages[stage] = stages.get(stage, 0) + 1
    return {
        "records": len(records),
        "forbidden_provenance_hits": forbidden_provenance_hits,
        "forbidden_text_hits": forbidden_text_hits,
        "stages": stages,
    }

"""Seed phase: decompose the task before extraction begins.

Produces key questions, extraction focus areas, and analytical framework
that guide extraction workers.
"""
from __future__ import annotations

import json

from .blackboard import Blackboard
from .models import ModelCaller, Signal, gen_signal_id
from .worker_dispatch import call_model


def generate_seed(blackboard: Blackboard,
                  caller: ModelCaller) -> tuple[dict, int]:
    """Read task and structural profiles, then produce an analytical plan.

    Returns (seed_plan, tokens_used).
    """
    doc_summary = "\n".join(
        f"- {d.name}: {d.size_bytes} bytes, {d.read_status}, "
        f"headings={d.headings[:20]}, "
        f"profile={json.dumps(d.structural_profile or {})}"
        for d in blackboard.documents
    )

    prompt = f"""You are a senior analyst planning an investigation. Before any documents are read in detail, you need to create an analytical plan.

TASK: {blackboard.task_instruction}

DOCUMENTS AVAILABLE (not yet read in detail — only structure/headings known):
{doc_summary}

Based on the task instruction and document structure, produce a plan:

1. KEY QUESTIONS: What specific questions must this investigation answer? Be concrete — "What is the total consideration?" not "Analyze financial terms." List 5-15 questions.

2. EXTRACTION FOCUS: For each document, what specific things should the extraction workers look for? Reference document names and section headings. Be specific — "In merger-agreement.docx, Section 4 (Representations), extract every individual representation and warranty" not "Read the agreement."

3. ANALYTICAL FRAMEWORK: What kind of analysis does this task require?
   - Is this an extraction task (pull out all terms/facts)?
   - A comparison task (compare two or more documents)?
   - A drafting task (produce a new document based on source material)?
   - An issue-flagging task (identify problems, risks, missing items)?
   - A calculation task (compute financial figures)?
   Describe the approach in 2-3 sentences.

4. CONTEXT ENRICHMENT NOTES: In plain language, enrich the task context before finalizing the plan. Do NOT build a fixed ontology, formal graph, or hard-coded entity schema. Instead, reason naturally about:
   - what domain, transaction, dispute, product, market, scientific question, software system, or other space the task appears to live in;
   - what explicit or implied people, organizations, assets, documents, rules, claims, metrics, time periods, or other objects matter;
   - what relationships or unknown slots must be resolved;
   - what subquestions workers should ask to turn unclear context into useful state.
   Fold the best of this thinking into the KEY QUESTIONS, EXTRACTION FOCUS, ANALYTICAL FRAMEWORK, and COMPLETENESS CRITERIA. Keep the notes unstructured and task-shaped; legal tasks may naturally mention parties, claims, pleadings, clauses, or authorities, while finance, science, market, software, or other tasks should use their own useful framing.

5. TASK STATE MAP: Create a temporary, task-induced coverage ledger in plain language. This is NOT a fixed ontology or formal graph. Identify the object rows that must be completed for this task and the fields/relationships needed to make each row judgeable. Examples across domains: custodians with role/status/device/deadline fields; comments with requested change/decision/rationale fields; asset-pool stats with source/calculation/table fields; clauses with counterparty edit/effect/recommendation fields. Include 3-10 rows.

6. COMPLETENESS CRITERIA: How will we know the investigation is thorough enough? What must the final deliverable contain to be considered complete? List 5-10 concrete criteria.

Return JSON:
{{"key_questions": ["question 1", "question 2"],
  "extraction_focus": [{{"document": "name", "focus": "what to look for"}}],
  "analytical_framework": "description of approach",
  "context_enrichment": "plain-language notes on task context, implied objects, relationships, unknown slots, and useful subquestions; no ontology or graph",
  "task_state_map": [
    {{
      "object_type": "task-shaped row type, e.g. custodian, comment, covenant, asset-pool statistic, markup issue",
      "required_fields": ["field workers must fill exactly"],
      "relationships": ["cross-document links or dependencies to resolve"],
      "closure_checks": ["how to know this row type is complete"],
      "worker_questions": ["targeted question workers should answer"]
    }}
  ],
  "completeness_criteria": ["criterion 1", "criterion 2"]}}"""

    payload, tokens = call_model(caller, prompt, max_tokens=4096)
    _ensure_task_state_map(payload)
    return payload, tokens


def seed_to_signals(seed: dict, blackboard: Blackboard) -> None:
    """Convert seed plan into blackboard signals that guide extraction."""
    for row in _task_state_map_rows(seed):
        blackboard.add_signal(Signal(
            id=gen_signal_id(), type="question",
            content=(
                f"Populate task-state row: {_format_task_state_map_row(row)} "
                f"fields={', '.join(row.get('required_fields', [])[:8])}; "
                f"closure={'; '.join(row.get('closure_checks', [])[:3])}"
            ),
            origin_entry="seed_plan", priority="high",
            status="open", iteration_created=0,
        ))

    for q in seed.get("key_questions", []):
        if isinstance(q, str) and q.strip():
            blackboard.add_signal(Signal(
                id=gen_signal_id(), type="question", content=q.strip(),
                origin_entry="seed_plan", priority="high",
                status="open", iteration_created=0,
            ))

    for focus in seed.get("extraction_focus", []):
        if isinstance(focus, dict):
            doc = focus.get("document", "")
            what = focus.get("focus", "")
            if doc and what:
                blackboard.add_signal(Signal(
                    id=gen_signal_id(), type="read_request",
                    content=f"In '{doc}': {what}",
                    origin_entry="seed_plan", priority="high",
                    status="open", iteration_created=0,
                ))


def _as_str_list(value: object) -> list[str]:
    if not isinstance(value, list):
        return []
    return [str(item).strip() for item in value if str(item).strip()]


def _task_state_map_rows(seed: dict) -> list[dict]:
    rows = seed.get("task_state_map", [])
    if not isinstance(rows, list):
        return []
    clean = []
    for row in rows[:12]:
        if not isinstance(row, dict):
            continue
        object_type = str(row.get("object_type", "")).strip()
        if not object_type:
            continue
        clean.append({
            "object_type": object_type,
            "required_fields": _as_str_list(row.get("required_fields", [])),
            "relationships": _as_str_list(row.get("relationships", [])),
            "closure_checks": _as_str_list(row.get("closure_checks", [])),
            "worker_questions": _as_str_list(row.get("worker_questions", [])),
        })
    return clean


def _ensure_task_state_map(seed: dict) -> None:
    if _task_state_map_rows(seed):
        seed["task_state_map"] = _task_state_map_rows(seed)
        return
    seed["task_state_map"] = [{
        "object_type": "task-required item",
        "required_fields": [
            "specific answer, extraction, comparison, calculation, or drafting element",
            "source support",
            "relationship to the user's requested deliverable",
            "artifact form needed in the final output",
        ],
        "relationships": [
            "connect each required item to the relevant source documents and key questions",
        ],
        "closure_checks": [
            "every key question and completeness criterion has a source-grounded answer, explicit gap, or required artifact element",
        ],
        "worker_questions": [
            "what rows, fields, calculations, classifications, or relationships must be completed for this task?",
        ],
    }]


def _format_task_state_map_row(row: dict) -> str:
    parts = [f"TASK STATE MAP ROW: {row.get('object_type', 'task object')}"]
    fields = row.get("required_fields") or []
    relationships = row.get("relationships") or []
    closure = row.get("closure_checks") or []
    questions = row.get("worker_questions") or []
    if fields:
        parts.append("Required fields: " + "; ".join(fields))
    if relationships:
        parts.append("Relationships to resolve: " + "; ".join(relationships))
    if closure:
        parts.append("Closure checks: " + "; ".join(closure))
    if questions:
        parts.append("Worker questions: " + "; ".join(questions))
    return ". ".join(parts)


def format_task_state_map(seed: dict) -> str:
    rows = _task_state_map_rows(seed)
    if not rows:
        return "None specified."
    return "\n".join(f"- {_format_task_state_map_row(row)}" for row in rows)

from __future__ import annotations

import json
import os
import re
import time
from dataclasses import asdict, dataclass, field
from pathlib import Path

from docx import Document as DocxDocument
from docx.shared import Pt

from .ingestion import discover_documents
from .providers.gemini import GeminiCaller
from .swarm import run_swarm
from .swarm.models import Task
from .swarm.survival_trace import (
    extract_artifact_texts,
    finalize_survival_trace,
)


@dataclass
class RunResult:
    task_id: str
    score: float | None = None
    criteria_pass: int = 0
    criteria_total: int = 0
    tokens_used: int = 0
    cost_usd: float = 0.0
    wall_clock_seconds: float = 0.0
    deliverable_files: list[str] = field(default_factory=list)
    error: str | None = None


def run_single_task(task_dir: Path, output_dir: Path, *,
                    worker_model: str | None = None,
                    synthesis_model: str | None = None,
                    task_id: str | None = None) -> RunResult:
    if not task_id:
        task_id = f"{task_dir.parent.name}/{task_dir.name}"
    t0 = time.time()

    task_json_path = task_dir / "task.json"
    if not task_json_path.exists():
        return RunResult(task_id=task_id, error="task.json not found")

    task_data = json.loads(task_json_path.read_text(encoding="utf-8"))
    deliverables_for_task = _deliverables_for_task(task_data)

    instruction = task_data.get("instructions", "")
    if not instruction:
        instruction_path = task_dir / "instruction.md"
        if instruction_path.exists():
            instruction = instruction_path.read_text(encoding="utf-8")

    if not instruction:
        return RunResult(task_id=task_id, error="no instruction found")

    documents = discover_documents(task_dir)
    if not documents:
        return RunResult(task_id=task_id, error="no documents found")

    w_model = worker_model or os.getenv("SWARM_WORKER_MODEL", "gemini-3.1-flash-lite")
    s_model = synthesis_model or os.getenv("SWARM_SYNTHESIS_MODEL", "gemini-3.5-flash")

    r_model = os.getenv("SWARM_REVIEWER_MODEL", "gemini-3.5-flash")

    worker_caller = GeminiCaller(model=w_model)
    synthesis_caller = GeminiCaller(model=s_model) if s_model != w_model else worker_caller
    reviewer_caller = GeminiCaller(model=r_model) if r_model else None

    out_dir = output_dir / task_id.replace("/", os.sep)
    out_dir.mkdir(parents=True, exist_ok=True)
    output_subdir = out_dir / "output"
    output_subdir.mkdir(exist_ok=True)

    task = Task(
        instruction=instruction,
        documents=documents,
        metadata={
            "task_id": task_id,
            "title": task_data.get("title", ""),
            "work_type": task_data.get("work_type", ""),
            "deliverables": deliverables_for_task,
        },
        output_dir=str(out_dir),
    )

    try:
        deliverable, blackboard = run_swarm(
            task, worker_caller,
            synthesis_caller=synthesis_caller,
            reviewer_caller=reviewer_caller,
        )
    except Exception as e:
        return RunResult(task_id=task_id, error=f"swarm error: {e}")

    deliverable_files = _write_deliverables(
        deliverable, deliverables_for_task, output_subdir,
    )
    artifact_texts = extract_artifact_texts(output_subdir, deliverable_files)
    finalize_survival_trace(out_dir, artifact_texts)

    wall_clock = time.time() - t0
    tokens = blackboard.total_tokens_used
    tokens_in = blackboard.tokens_input
    tokens_out = blackboard.tokens_output

    # Cost calculation per model
    MODEL_PRICING = {
        "gemini-3.1-flash-lite": {"input": 0.25, "output": 1.50},
        "gemini-3-flash-preview": {"input": 0.50, "output": 3.00},
        "gemini-3.5-flash": {"input": 1.50, "output": 9.00},
        "gemini-3.1-pro-preview": {"input": 2.00, "output": 12.00},
    }
    DEFAULT_PRICING = {"input": 0.25, "output": 1.50}

    cost_total = 0.0
    cost_breakdown = {}
    for model, usage in blackboard.cost_by_model.items():
        pricing = MODEL_PRICING.get(model, DEFAULT_PRICING)
        model_cost_in = usage["input"] * pricing["input"] / 1_000_000
        model_cost_out = usage["output"] * pricing["output"] / 1_000_000
        model_cost = model_cost_in + model_cost_out
        cost_total += model_cost
        cost_breakdown[model] = {
            "input_tokens": usage["input"],
            "output_tokens": usage["output"],
            "total_tokens": usage["total"],
            "calls": usage["calls"],
            "cost_usd": round(model_cost, 4),
        }

    # Fallback if no per-model tracking
    if not cost_breakdown:
        fallback_pricing = DEFAULT_PRICING
        cost_total = (tokens_in * fallback_pricing["input"] + tokens_out * fallback_pricing["output"]) / 1_000_000

    metrics = {
        "documents_read": len(documents),
        "total_vdr_files": len(documents),
        "documents_skipped": 0,
        "documents_read_list": [d.name for d in documents],
        "documents_skipped_list": [],
        "input_tokens": tokens_in,
        "output_tokens": tokens_out,
        "total_tokens": tokens,
        "cost_total_usd": round(cost_total, 4),
        "cost_by_model": cost_breakdown,
        "wall_clock_seconds": wall_clock,
    }
    (out_dir / "metrics.json").write_text(
        json.dumps(metrics, indent=2), encoding="utf-8",
    )

    status = {
        "task_id": task_id,
        "status": "completed",
        "tokens_used": tokens,
        "wall_clock_seconds": wall_clock,
        "deliverable_files": deliverable_files,
    }
    (out_dir / "status.json").write_text(
        json.dumps(status, indent=2), encoding="utf-8",
    )

    return RunResult(
        task_id=task_id,
        tokens_used=tokens,
        wall_clock_seconds=wall_clock,
        deliverable_files=deliverable_files,
    )


def _write_deliverables(deliverable: str | dict[str, str], deliverables_map: dict,
                        output_dir: Path) -> list[str]:
    files_written = []

    if deliverables_map:
        for filename in deliverables_map.values():
            path = output_dir / filename
            suffix = Path(filename).suffix.lower()
            content = _content_for_file(deliverable, filename)
            if suffix == ".docx":
                _write_docx(path, content)
            elif suffix == ".xlsx":
                _write_xlsx(path, content)
            else:
                path.write_text(content, encoding="utf-8")
            files_written.append(filename)
    else:
        _write_docx(output_dir / "output.docx", _content_for_file(deliverable, "output.docx"))
        files_written.append("output.docx")

    return files_written


def _deliverables_for_task(task_data: dict) -> dict[str, str]:
    deliverables_map = task_data.get("deliverables", {})
    if isinstance(deliverables_map, dict) and deliverables_map:
        return {
            str(key): str(value)
            for key, value in deliverables_map.items()
            if isinstance(value, str) and value.strip()
        }
    return {}


def _content_for_file(deliverable: str | dict[str, str], filename: str) -> str:
    if isinstance(deliverable, dict):
        if filename in deliverable:
            return deliverable[filename]
        stem = Path(filename).name
        if stem in deliverable:
            return deliverable[stem]
        available = ", ".join(sorted(str(k) for k in deliverable)) or "<none>"
        raise KeyError(
            f"No synthesized content for {filename}; available files: {available}"
        )
    return deliverable


def _write_docx(path: Path, text: str) -> None:
    doc = DocxDocument()
    style = doc.styles["Normal"]
    style.font.size = Pt(11)
    style.font.name = "Calibri"

    for line in text.split("\n"):
        stripped = line.strip()
        if not stripped:
            doc.add_paragraph("")
            continue
        if stripped.startswith("# "):
            doc.add_heading(stripped[2:], level=1)
        elif stripped.startswith("## "):
            doc.add_heading(stripped[3:], level=2)
        elif stripped.startswith("### "):
            doc.add_heading(stripped[4:], level=3)
        elif stripped.startswith("- ") or stripped.startswith("* "):
            doc.add_paragraph(stripped[2:], style="List Bullet")
        elif re.match(r'^\d+[.)] ', stripped):
            text_after = re.sub(r'^\d+[.)] ', '', stripped)
            doc.add_paragraph(text_after, style="List Number")
        elif stripped.startswith("#### "):
            doc.add_heading(stripped[5:], level=4)
        else:
            doc.add_paragraph(stripped)

    doc.save(str(path))


def _write_xlsx(path: Path, text: str) -> None:
    import openpyxl

    wb = openpyxl.Workbook()
    ws = wb.active
    ws.title = "Analysis"

    def sanitize_sheet_name(name: str) -> str:
        cleaned = re.sub(r"[\[\]\*\?/\\:]", " ", name).strip() or "Sheet"
        return cleaned[:31]

    def ensure_sheet(name: str):
        title = sanitize_sheet_name(name)
        if title in wb.sheetnames:
            return wb[title]
        if not ws._cells and ws.title == "Analysis":
            ws.title = title
            return ws
        return wb.create_sheet(title)

    current = ws
    for line in text.split("\n"):
        stripped = line.strip()
        if not stripped:
            continue
        sheet_match = re.match(r"^#{1,3}\s*Sheet:\s*(.+)$", stripped, re.IGNORECASE)
        if sheet_match:
            current = ensure_sheet(sheet_match.group(1))
            continue
        if re.match(r"^\|?\s*:?-{3,}:?\s*(\|\s*:?-{3,}:?\s*)+\|?$", stripped):
            continue
        if "|" in stripped and stripped.count("|") >= 2:
            cells = [cell.strip() for cell in stripped.strip("|").split("|")]
            current.append(cells)
        else:
            current.append([stripped])

    wb.save(str(path))

from __future__ import annotations

import json
import os
import re
import threading
import uuid
from concurrent.futures import ThreadPoolExecutor
from typing import Any

from .blackboard import Blackboard
from .models import (
    Entry, EntrySource, EpistemicStatus, ModelCaller, WorkerOutput, WorkerRecord,
    gen_entry_id,
)
from .section_index import resolve_section_text


_usage_state = threading.local()


def call_model(caller: ModelCaller, prompt: str, *,
               max_tokens: int = 8192, json_mode: bool = True,
               audit_context: Any = None) -> tuple[dict, int]:
    """Returns (payload, total_tokens)."""
    if audit_context is not None:
        from .prompt_audit import audit_prompt
        audit_prompt(prompt, audit_context)
    result = caller.complete(prompt, max_tokens=max_tokens, json_mode=json_mode)
    tokens = result.tokens_total
    by_model = {
        result.model: {
            "input": result.tokens_input,
            "output": result.tokens_output,
            "total": result.tokens_total,
            "calls": 1,
        }
    }
    _usage_state.last_model = result.model
    _usage_state.last_in = result.tokens_input
    _usage_state.last_out = result.tokens_output
    _usage_state.last_by_model = by_model
    _record_aggregate_usage(result)
    text = result.text.strip()

    if not json_mode:
        return {"text": text}, tokens

    if text.startswith("```"):
        text = re.sub(r"^```\w*\n?", "", text)
        text = re.sub(r"\n?```$", "", text)

    try:
        payload = json.loads(text)
        if not isinstance(payload, dict):
            payload = {"value": payload}
        return payload, tokens
    except json.JSONDecodeError:
        # Find JSON by bracket counting (avoids greedy regex issues)
        for i, ch in enumerate(text):
            if ch == '{':
                depth = 0
                for j in range(i, len(text)):
                    if text[j] == '{':
                        depth += 1
                    elif text[j] == '}':
                        depth -= 1
                    if depth == 0:
                        try:
                            return json.loads(text[i:j + 1]), tokens
                        except json.JSONDecodeError:
                            break
                break
        return {"findings": [], "parse_error": True}, tokens


def begin_call_model_usage() -> None:
    _usage_state.usage_aggregate = {}


def end_call_model_usage() -> None:
    aggregate = getattr(_usage_state, "usage_aggregate", None)
    if aggregate is None:
        return
    _usage_state.last_by_model = aggregate
    if aggregate:
        first_model = next(iter(aggregate))
        _usage_state.last_model = first_model
        _usage_state.last_in = sum(v["input"] for v in aggregate.values())
        _usage_state.last_out = sum(v["output"] for v in aggregate.values())
    _usage_state.usage_aggregate = None


def get_last_call_usage() -> tuple[dict, str, int, int]:
    return (
        getattr(_usage_state, "last_by_model", None),
        getattr(_usage_state, "last_model", ""),
        getattr(_usage_state, "last_in", 0),
        getattr(_usage_state, "last_out", 0),
    )


def set_last_call_usage(by_model: dict | None) -> None:
    """Install aggregate usage for callers that coordinate parallel model calls."""
    if not by_model:
        _usage_state.last_by_model = {}
        _usage_state.last_model = ""
        _usage_state.last_in = 0
        _usage_state.last_out = 0
        return

    _usage_state.last_by_model = by_model
    _usage_state.last_model = next(iter(by_model))
    _usage_state.last_in = sum(v.get("input", 0) for v in by_model.values())
    _usage_state.last_out = sum(v.get("output", 0) for v in by_model.values())


def merge_call_usage(by_model: dict | None) -> None:
    """Merge externally collected usage into the active aggregate, if any."""
    if not isinstance(by_model, dict):
        return
    aggregate = getattr(_usage_state, "usage_aggregate", None)
    if aggregate is None:
        return
    for model, usage in by_model.items():
        if model not in aggregate:
            aggregate[model] = {"input": 0, "output": 0, "total": 0, "calls": 0}
        aggregate[model]["input"] += usage.get("input", 0)
        aggregate[model]["output"] += usage.get("output", 0)
        aggregate[model]["total"] += usage.get("total", 0)
        aggregate[model]["calls"] += usage.get("calls", 0)


def _record_aggregate_usage(result) -> None:
    aggregate = getattr(_usage_state, "usage_aggregate", None)
    if aggregate is None:
        return
    if result.model not in aggregate:
        aggregate[result.model] = {"input": 0, "output": 0, "total": 0, "calls": 0}
    aggregate[result.model]["input"] += result.tokens_input
    aggregate[result.model]["output"] += result.tokens_output
    aggregate[result.model]["total"] += result.tokens_total
    aggregate[result.model]["calls"] += 1


def compose_worker_prompt(task_description: str, context_entries: list[Entry],
                          document_sections: list[tuple[str, str]],
                          task_instruction: str,
                          assigned_signals: list[tuple[str, str, str]] | None = None) -> str:
    parts = [task_description, f"\nOVERALL TASK: {task_instruction}"]

    if context_entries:
        parts.append("\nRELEVANT PRIOR FINDINGS:")
        for entry in context_entries:
            warning = ""
            if entry.epistemic and entry.epistemic.classification in (
                "adversarial_claim", "strategic"
            ):
                warning = f" [CAUTION: {entry.epistemic.classification}]"
            parts.append(
                f"  [{entry.id}] ({entry.type}, conf={entry.confidence:.1f}) "
                f"{entry.content[:300]}{warning}"
            )

    if assigned_signals:
        parts.append("\nASSIGNED OPEN SIGNALS:")
        for sig_id, priority, content in assigned_signals:
            parts.append(f"  [{sig_id}] ({priority}) {content[:500]}")
        parts.append(
            "When a finding addresses an assigned signal, include that exact "
            "signal ID in the finding's addresses_signals array."
        )

    if document_sections:
        parts.append("\nSOURCE MATERIAL:")
        for header, text in document_sections:
            parts.append(f"\n### {header}\n{text}")

    parts.append("""
OUTPUT: Return JSON with a "findings" array. Each finding:
{
  "type": "observation | analysis | calculation | strategy | gap",
  "content": "specific finding with exact numbers/citations",
  "source_document": "name or null", "source_section": "section or null",
  "evidence": "exact quote or calculation steps",
  "confidence": 0.0-1.0,
  "epistemic_classification": "fact | adversarial_claim | expert_opinion | inference | strategic",
  "epistemic_motivation": "whose interests does this serve?",
  "tags": ["topic"],
  "opens_questions": ["new questions — max 5"],
  "supports_entries": ["e3", "e7"],
  "contradicts_entries": ["entry IDs"],
  "supersedes_entries": ["entry IDs"],
  "addresses_signals": ["s2", "s5"]
}

RULES:
- Be SPECIFIC: "$2,541,500" not "a large amount". Include EXACT dollar amounts, dates, percentages.
- Show arithmetic: "35% × $7,261,428 = $2,541,500"
- ENUMERATE every individual item — list each one separately, do NOT summarize groups
- Every dollar amount, date, deadline, party name, defined term = separate finding
- Every numbered clause, schedule item, exhibit entry = separate finding
- Reference prior findings by ID when supporting or contradicting
- Flag adversarial sources
- Max 5 opens_questions per finding
- If you cannot determine something, return type "gap"
- Aim for HIGH DENSITY: 15-40 findings per worker call. Fewer than 10 means you are summarizing.
""")
    return "\n".join(parts)


def _assigned_signal_ids(task: dict, blackboard: Blackboard) -> list[str]:
    open_signal_ids = {
        s.id for s in blackboard.signals
        if s.status == "open" and s.priority in ("critical", "high")
    }
    assigned: list[str] = []
    for sig_id in task.get("addresses_signals", []):
        if not isinstance(sig_id, str):
            continue
        if sig_id in open_signal_ids and sig_id not in assigned:
            assigned.append(sig_id)
    return assigned


def _assigned_signal_details(
    signal_ids: list[str], blackboard: Blackboard,
) -> list[tuple[str, str, str]]:
    by_id = {s.id: s for s in blackboard.signals}
    details: list[tuple[str, str, str]] = []
    for sig_id in signal_ids:
        signal = by_id.get(sig_id)
        if signal:
            details.append((signal.id, signal.priority, signal.content))
    return details


def _attach_assigned_signal_ids(entries: list[Entry], signal_ids: list[str]) -> None:
    if not entries or not signal_ids:
        return
    eligible = [entry for entry in entries if passes_quality_gate(entry)]
    if not eligible:
        return
    already_addressed = {
        sig_id
        for entry in eligible
        for sig_id in entry.addresses_signals
    }
    missing_ids = [sig_id for sig_id in signal_ids if sig_id not in already_addressed]
    if not missing_ids:
        return
    target = max(
        eligible,
        key=lambda entry: (
            entry.type in ANALYTICAL_TYPES,
            entry.confidence,
            len(entry.content),
        ),
    )
    target.addresses_signals.extend(missing_ids)


def parse_worker_output(payload: dict, iteration: int,
                        worker_id: str, task_description: str) -> list[Entry]:
    findings = payload.get("findings", [])
    entries = []
    for f in findings:
        if not isinstance(f, dict):
            continue
        content = str(f.get("content", "")).strip()
        if not content or len(content) < 20:
            continue
        entry_type = f.get("type", "observation")
        if entry_type not in (
            "observation", "analysis", "calculation", "strategy", "contradiction", "gap"
        ):
            entry_type = "observation"

        source = None
        if f.get("source_document"):
            source = EntrySource(
                f["source_document"], f.get("source_section"),
                str(f.get("evidence", "")),
            )

        epistemic = EpistemicStatus(
            f.get("epistemic_classification", "inference"), "unknown",
            str(f.get("epistemic_motivation", "")),
        )

        try:
            conf = float(f.get("confidence", 0.5))
        except (ValueError, TypeError):
            conf = 0.5

        def _as_list(val):
            return val if isinstance(val, list) else []

        entries.append(Entry(
            id=gen_entry_id(), type=entry_type, content=content,
            source=source, epistemic=epistemic,
            created_by=WorkerRecord(worker_id, task_description, iteration),
            confidence=conf,
            tags=_as_list(f.get("tags", [])), status="active",
            opens_questions=_as_list(f.get("opens_questions", []))[:5],
            supports_entries=_as_list(f.get("supports_entries", [])),
            contradicts_entries=_as_list(f.get("contradicts_entries", [])),
            supersedes_entries=_as_list(f.get("supersedes_entries", [])),
            addresses_signals=_as_list(f.get("addresses_signals", [])),
        ))
    return entries


def passes_quality_gate(entry: Entry) -> bool:
    if not entry.content or len(entry.content.strip()) < 20:
        return False
    if entry.type == "observation" and (not entry.source or not entry.source.document):
        return False
    if entry.type == "calculation":
        has_nums = sum(1 for c in entry.content if c.isdigit()) >= 2
        has_op = any(op in entry.content for op in ("=", "+", "×", "*", "/", "%", "−"))
        if not (has_nums and has_op):
            return False
    return True


ANALYTICAL_TYPES = {"analysis", "calculation", "strategy"}


def execute_workers_parallel(worker_tasks: list[dict], blackboard: Blackboard,
                             caller: ModelCaller, *,
                             analytical_caller: ModelCaller | None = None) -> list[WorkerOutput]:
    def run_one(task: dict) -> WorkerOutput:
        wid = f"w{blackboard.iteration}_{uuid.uuid4().hex[:4]}"
        assigned_ids = _assigned_signal_ids(task, blackboard)
        assigned_signals = _assigned_signal_details(assigned_ids, blackboard)
        context_entries = blackboard.get_entries_by_ids(
            task.get("reads_from_blackboard", [])
        )
        doc_sections: list[tuple[str, str]] = []
        sections_read: list[tuple[str, str]] = []
        for spec in task.get("reads_from_documents", []):
            doc_name = spec.get("document", "")
            for ds in blackboard.documents:
                if ds.name == doc_name:
                    for sec_name in spec.get("sections", ["Full Document"]):
                        text = resolve_section_text(
                            ds.text, ds.section_index, sec_name,
                        )
                        doc_sections.append((f"{doc_name} — {sec_name}", text))
                        sections_read.append((doc_name, sec_name))
                    break

        prompt = compose_worker_prompt(
            task["description"], context_entries,
            doc_sections, blackboard.task_instruction, assigned_signals,
        )
        # Route analytical workers to smarter model if available
        expected_type = task.get("expected_output_type", "observation")
        use_caller = caller
        if analytical_caller and expected_type in ANALYTICAL_TYPES:
            use_caller = analytical_caller
        result = use_caller.complete(prompt, max_tokens=8192, json_mode=True)
        t_in = result.tokens_input
        t_out = result.tokens_output
        tokens = result.tokens_total
        text = result.text.strip()
        if text.startswith("```"):
            text = re.sub(r"^```\w*\n?", "", text)
            text = re.sub(r"\n?```$", "", text)
        try:
            payload = json.loads(text)
            if not isinstance(payload, dict):
                payload = {"value": payload}
        except json.JSONDecodeError:
            for i, ch in enumerate(text):
                if ch == '{':
                    depth = 0
                    for j in range(i, len(text)):
                        if text[j] == '{':
                            depth += 1
                        elif text[j] == '}':
                            depth -= 1
                        if depth == 0:
                            try:
                                payload = json.loads(text[i:j + 1])
                            except json.JSONDecodeError:
                                payload = None
                            break
                    break
            if not payload:
                payload = {"findings": [], "parse_error": True}
        entries = parse_worker_output(
            payload, blackboard.iteration, wid, task["description"],
        )
        _attach_assigned_signal_ids(entries, assigned_ids)
        return WorkerOutput(entries, tokens, t_in, t_out, result.model, wid, task, sections_read)

    if not worker_tasks:
        return []
    max_w = min(len(worker_tasks), int(os.getenv("SWARM_MAX_WORKERS", "5")))
    with ThreadPoolExecutor(max_workers=max_w) as pool:
        futures = [pool.submit(run_one, t) for t in worker_tasks]
        results = []
        for f in futures:
            try:
                results.append(f.result())
            except Exception:
                pass
        return results

from __future__ import annotations

import hashlib
import json
from pathlib import Path

from ..swarm.models import Document
from .docx import read_docx
from .pdf import read_pdf
from .xlsx import read_xlsx
from .pptx import read_pptx
from .text import read_text
from .eml import read_eml

SUPPORTED_EXTENSIONS = {
    ".txt", ".md", ".json",
    ".docx", ".xlsx", ".pptx",
    ".pdf", ".eml",
}

_READERS = {
    ".docx": read_docx,
    ".xlsx": read_xlsx,
    ".pptx": read_pptx,
    ".pdf": read_pdf,
    ".eml": read_eml,
}


def ingest_file(path: Path) -> Document:
    suffix = path.suffix.lower()
    name = path.name
    size_bytes = path.stat().st_size
    doc_id = f"doc_{hashlib.md5(name.encode()).hexdigest()[:8]}"

    reader = _READERS.get(suffix, read_text)
    text, structured = reader(path)

    return Document(
        id=doc_id,
        name=name,
        text=text,
        size_bytes=size_bytes,
        metadata={"extension": suffix, "path": str(path)},
        structured=structured,
    )


def ingest_directory(directory: Path) -> list[Document]:
    docs = []
    for path in sorted(directory.rglob("*")):
        if path.is_file() and path.suffix.lower() in SUPPORTED_EXTENSIONS:
            docs.append(ingest_file(path))
    return docs


def discover_documents(task_dir: Path) -> list[Document]:
    for subdir_name in ("source_documents", "input_documents", "documents", "docs"):
        subdir = task_dir / subdir_name
        if subdir.is_dir():
            return ingest_directory(subdir)
    return [
        ingest_file(p)
        for p in sorted(task_dir.iterdir())
        if p.is_file()
        and p.suffix.lower() in SUPPORTED_EXTENSIONS
        and p.name not in ("task.json", "instruction.md", "scores.json", "status.json")
    ]

