input.command:
# Find a task that scored well (high pass rate) with a good-sized blackboard
$base = "results\cycle23_full_all_e6d1a70"
# Check a few different practice areas for variety
$tasks = @(
    "emerging-companies-venture-capital",
    "data-privacy-cybersecurity", 
    "funds-asset-management",
    "corporate-ma"
)
foreach ($family in $tasks) {
    $familyPath = Join-Path $base $family
    if (Test-Path $familyPath) {
        $subtasks = Get-ChildItem $familyPath -Directory | Select-Object -First 3
        foreach ($t in $subtasks) {
            $swarmDir = Join-Path $t.FullName "swarm"
            if (Test-Path $swarmDir) {
                $bbs = Get-ChildItem $swarmDir -Filter "blackboard_iter_*.json" | Sort-Object Name
                $final = $bbs | Select-Object -Last 1
                if ($final) {
                    $size = [math]::Round($final.Length / 1KB, 1)
                    $taskId = "$family/$($t.Name)"
                    Write-Output "$taskId — final blackboard: $size KB ($($bbs.Count) snapshots)"
                }
            }
        }
    }
}

$base = "results\cycle23_full_all_e6d1a70"
# Check the 24 practice area folder sizes
Get-ChildItem $base -Directory | ForEach-Object {
    $size = (Get-ChildItem $_.FullName -Recurse -File | Measure-Object -Property Length -Sum).Sum / 1MB
    "$($_.Name) — $([math]::Round($size, 0)) MB"
} | Sort-Object { [int]($_ -split ' — ')[1].Replace(' MB','') } -Descending

# Find tasks from the strongest practice areas that had high scores
$base = "results\cycle23_full_all_e6d1a70"
$candidates = @(
    "data-privacy-cybersecurity\analyze-cpra-compliance-gaps-against-current-privacy-program",
    "emerging-companies-venture-capital\analyze-counterparty-markup-of-bridge-loan-agreement",
    "funds-asset-management\analyze-counterparty-markup-of-investment-advisory-agreement",
    "corporate-ma\analyze-change-of-control-provisions-across-targets-material-contracts"
)
foreach ($task in $candidates) {
    $taskDir = Join-Path $base $task
    $scoresPath = Join-Path $taskDir "scores.json"
    if (Test-Path $scoresPath) {
        $scores = Get-Content $scoresPath -Raw | ConvertFrom-Json
        $passed = $scores.criteria_results | Where-Object { $_.pass -eq $true }
        $total = $scores.criteria_results.Count
        $passCount = $passed.Count
        Write-Output "$task — $passCount/$total criteria passed"
    }
}

